"use client";

import { useTranslations } from "next-intl";
import { useOrganization } from "@clerk/nextjs";
import { useQuery, useMutation } from "convex/react";
import { api } from "@/convex/_generated/api";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Card, CardContent } from "@/components/ui/card";
import { useState } from "react";
import { PlusIcon, TrashIcon } from "@heroicons/react/24/outline";

type Gender = "male" | "female" | "mixed";
type DivisionType = "alphabetic" | "greek" | "numeric";

interface AgeCategory {
  id: string;
  name: string;
  minAge: number;
  maxAge: number;
}

export function TeamConfigSettings() {
  const t = useTranslations("Settings.general.teamConfig");
  const { organization } = useOrganization();
  const [newCategory, setNewCategory] = useState<Partial<AgeCategory>>({});

  const teamConfig = useQuery(
    api.leagueSettings.getTeamConfig,
    organization?.slug ? { leagueSlug: organization.slug } : "skip"
  );

  const addAgeCategory = useMutation(api.leagueSettings.addAgeCategory);
  const removeAgeCategory = useMutation(api.leagueSettings.removeAgeCategory);
  const updateEnabledGenders = useMutation(
    api.leagueSettings.updateEnabledGenders
  );
  const updateHorizontalDivisions = useMutation(
    api.leagueSettings.updateHorizontalDivisions
  );

  if (!organization || !teamConfig) {
    return null;
  }

  const handleAddCategory = async () => {
    if (!newCategory.name || !newCategory.minAge || !newCategory.maxAge) {
      return;
    }

    await addAgeCategory({
      leagueSlug: organization.slug,
      category: {
        id: crypto.randomUUID(),
        name: newCategory.name,
        minAge: newCategory.minAge,
        maxAge: newCategory.maxAge,
      },
    });

    setNewCategory({});
  };

  const handleRemoveCategory = async (categoryId: string) => {
    await removeAgeCategory({
      leagueSlug: organization.slug,
      categoryId,
    });
  };

  const handleGenderToggle = async (gender: Gender) => {
    const currentGenders = teamConfig.enabledGenders;
    const newGenders = currentGenders.includes(gender)
      ? currentGenders.filter((g) => g !== gender)
      : [...currentGenders, gender];

    await updateEnabledGenders({
      leagueSlug: organization.slug,
      enabledGenders: newGenders,
    });
  };

  const handleDivisionToggle = async (enabled: boolean) => {
    await updateHorizontalDivisions({
      leagueSlug: organization.slug,
      horizontalDivisions: enabled
        ? {
            enabled: true,
            type: teamConfig.horizontalDivisions?.type || "alphabetic",
          }
        : undefined,
    });
  };

  const handleDivisionTypeChange = async (type: DivisionType) => {
    await updateHorizontalDivisions({
      leagueSlug: organization.slug,
      horizontalDivisions: {
        enabled: true,
        type,
      },
    });
  };

  return (
    <div className="space-y-6">
      {/* Age Categories Section */}
      <div className="space-y-4">
        <div>
          <h3 className="text-lg font-medium">{t("ageCategories.title")}</h3>
          <p className="text-sm text-muted-foreground">
            {t("ageCategories.description")}
          </p>
        </div>

        <div className="space-y-2">
          {teamConfig.ageCategories.length === 0 ? (
            <p className="text-sm text-muted-foreground">
              {t("ageCategories.empty")}
            </p>
          ) : (
            teamConfig.ageCategories.map((category) => (
              <Card key={category.id}>
                <CardContent className="flex items-center justify-between p-4">
                  <div className="space-y-1">
                    <p className="font-medium">{category.name}</p>
                    <p className="text-sm text-muted-foreground">
                      {category.minAge} - {category.maxAge} years
                    </p>
                  </div>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => handleRemoveCategory(category.id)}
                  >
                    <TrashIcon className="h-4 w-4" />
                  </Button>
                </CardContent>
              </Card>
            ))
          )}
        </div>

        <div className="grid grid-cols-4 gap-2">
          <div className="col-span-2">
            <Label htmlFor="categoryName">{t("ageCategories.name")}</Label>
            <Input
              id="categoryName"
              value={newCategory.name || ""}
              onChange={(e) =>
                setNewCategory({ ...newCategory, name: e.target.value })
              }
              placeholder={t("ageCategories.name")}
            />
          </div>
          <div>
            <Label htmlFor="minAge">{t("ageCategories.minAge")}</Label>
            <Input
              id="minAge"
              type="number"
              value={newCategory.minAge || ""}
              onChange={(e) =>
                setNewCategory({
                  ...newCategory,
                  minAge: parseInt(e.target.value),
                })
              }
              placeholder="0"
            />
          </div>
          <div>
            <Label htmlFor="maxAge">{t("ageCategories.maxAge")}</Label>
            <Input
              id="maxAge"
              type="number"
              value={newCategory.maxAge || ""}
              onChange={(e) =>
                setNewCategory({
                  ...newCategory,
                  maxAge: parseInt(e.target.value),
                })
              }
              placeholder="0"
            />
          </div>
        </div>
        <Button onClick={handleAddCategory} variant="outline" className="w-full">
          <PlusIcon className="mr-2 h-4 w-4" />
          {t("ageCategories.add")}
        </Button>
      </div>

      {/* Enabled Genders Section */}
      <div className="space-y-4">
        <div>
          <h3 className="text-lg font-medium">{t("genders.title")}</h3>
          <p className="text-sm text-muted-foreground">
            {t("genders.description")}
          </p>
        </div>

        <div className="space-y-2">
          {(["male", "female", "mixed"] as Gender[]).map((gender) => (
            <div key={gender} className="flex items-center space-x-2">
              <Checkbox
                id={gender}
                checked={teamConfig.enabledGenders.includes(gender)}
                onCheckedChange={() => handleGenderToggle(gender)}
              />
              <Label htmlFor={gender} className="cursor-pointer">
                {t(`genders.${gender}`)}
              </Label>
            </div>
          ))}
        </div>
      </div>

      {/* Horizontal Divisions Section */}
      <div className="space-y-4">
        <div>
          <h3 className="text-lg font-medium">{t("divisions.title")}</h3>
          <p className="text-sm text-muted-foreground">
            {t("divisions.description")}
          </p>
        </div>

        <div className="space-y-4">
          <div className="flex items-center space-x-2">
            <Checkbox
              id="divisionsEnabled"
              checked={teamConfig.horizontalDivisions?.enabled || false}
              onCheckedChange={handleDivisionToggle}
            />
            <Label htmlFor="divisionsEnabled" className="cursor-pointer">
              {t("divisions.enabled")}
            </Label>
          </div>

          {teamConfig.horizontalDivisions?.enabled && (
            <div className="space-y-2">
              <Label htmlFor="divisionType">{t("divisions.type")}</Label>
              <Select
                value={teamConfig.horizontalDivisions.type}
                onValueChange={(value) =>
                  handleDivisionTypeChange(value as DivisionType)
                }
              >
                <SelectTrigger id="divisionType">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="alphabetic">
                    {t("divisions.alphabetic")}
                  </SelectItem>
                  <SelectItem value="greek">{t("divisions.greek")}</SelectItem>
                  <SelectItem value="numeric">
                    {t("divisions.numeric")}
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
